<?php function pal($s){for($i=0,$j=strlen($s)-1;$i<$j;$i++,$j--)if($s[$i]!=$s[$j])return false;return true;}function solve($w){$pos=[];foreach($w as $i=>$s)$pos[$s]=$i;$ans=[];foreach($w as $i=>$s){for($c=0;$c<=strlen($s);$c++){$pre=substr($s,0,$c);$suf=substr($s,$c);$r=strrev($suf);if(pal($pre)&&array_key_exists($r,$pos)&&$pos[$r]!=$i)$ans[]=[$pos[$r],$i];$r=strrev($pre);if($c<strlen($s)&&pal($suf)&&array_key_exists($r,$pos)&&$pos[$r]!=$i)$ans[]=[$i,$pos[$r]];}}usort($ans,fn($a,$b)=>$a[0]==$b[0]?$a[1]-$b[1]:$a[0]-$b[0]);return $ans;}function fmt($p){return "[".implode(",",array_map(fn($q)=>"[{$q[0]},{$q[1]}]",$p))."]";}$d=preg_split('/\s+/',trim(stream_get_contents(STDIN)));if(count($d)&&$d[0]!==""){$idx=0;$t=intval($d[$idx++]);$out=[];for($tc=0;$tc<$t;$tc++){$n=intval($d[$idx++]);$w=[];for($i=0;$i<$n;$i++){$w[]=$d[$idx]=="_"?"":$d[$idx];$idx++;}$out[]=fmt(solve($w));}echo implode("\n\n",$out);}
?>
